```scala
import scala.collection.mutable

object Solution {
  /**
    * @param nums The strictly increasing integer array.
    * @param queries The list of [l_i, r_i] queries.
    * @return An array containing the minimum total cost for each query.
    */
  def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val n = nums.length

    // 1. Precompute closest(x) for all x
    val closest = Array.ofDim[Int](n)
    for (x <- 0 until n) {
      var minDiff: Long = Long.MaxValue
      var bestY: Int = -1

      // Check neighbors (x-1 and x+1)
      val neighbors = mutable.ArrayBuffer[Int]()
      if (x > 0) neighbors.+=`(x - 1)`
      if (x < n - 1) neighbors.+=`(x + 1)`

      if (neighbors.isEmpty) {
        closest(x) = x
        continue
      }

      for (y <- neighbors) {
        val diff = Math.abs(nums(x) - nums(y))
        if (diff < minDiff) {
          minDiff = diff
          bestY = y
        } else if (diff == minDiff) {
          // If differences are the same, choose the smaller index
          if (y < bestY || bestY == -1) {
            bestY = y
          }
        }
      }
      closest(x) = bestY
    }

    // 2. Process Queries using BFS/Dijkstra on the 'closest' move graph structure
    val results = Array.ofDim[Long](queries.length)
    for ((i, query) <- queries.zipWithIndex) {
      val l = query(0).toInt
      val r = query(1).toInt

      // Initial cost: direct jump from l to r
      var minCost: Long = Math.abs(nums(l) - nums(r))

      // BFS to explore all states reachable from l using only 'closest' moves,
      // while simultaneously checking the transition cost to r.

      // Map: index -> minimum cost from l using only 'closest' moves
      val reachable = mutable.Map[Int, Long]()
      val queue = mutable.ArrayBuffer[Int]()

      reachable.put(l, 0L)
      queue.append(l)
      var head = 0

      while (head < queue.length) {
        val u = queue(head)
        head += 1
        val costU = reachable(u)

        // Check the path: l -> ... -> u (cost costU) -> r (direct jump)
        val directCostToR = Math.abs(nums(u) - nums(r))
        minCost = Math.min(minCost, costU + directCostToR)

        // Explore next closest move: u -> closest(u)
        val v = closest(u)
        val newCostV = costU + 1

        // If v is unvisited or we found a strictly cheaper path to v (though here, cost is always 1)
        if (!reachable.contains(v) || newCostV < reachable(v)) {
          reachable.put(v, newCostV)
          queue.append(v)
        }
      }

      // If r was reached purely by closest moves, the cost is stored in reachable(r)
      if (reachable.contains(r)) {
        minCost = Math.min(minCost, reachable(r))
      }

      results(i) = minCost
    }

    results
  }
}
