import scala.collection.mutable

object Solution {
  /**
    * @param nums The strictly increasing integer array.
    * @param queries The queries [l_i, r_i].
    * @return An array of minimum total costs.
    */
  def solve(nums: Array[Long], queries: Array[Array[Int]]): Array[Long] = {
    val n = nums.length

    // 1. Precompute closest(x) for all x
    val closest = Array.ofDim[Int](n)
    for (x <- 0 until n) {
      var minDiff: Long = Long.MaxValue
      var bestY: Int = -1

      // Check neighbors (x-1 and x+1)
      val neighbors = mutable.ArrayBuffer[Int]()
      if (x > 0) neighbors.append(x - 1)
      if (x < n - 1) neighbors.append(x + 1)

      if (neighbors.isEmpty) {
        // Should not happen since n >= 2
        closest(x) = x
        continue
      }

      for (y <- neighbors) {
        val diff = Math.abs(nums(x) - nums(y))
        if (diff < minDiff) {
          minDiff = diff
          bestY = y
        } else if (diff == minDiff) {
          // If differences are the same, choose the smaller index
          if (y < bestY || bestY == -1) {
            bestY = y
          }
        }
      }
      closest(x) = bestY
    }

    // 2. Answer Queries using BFS on the 'closest' graph structure
    val results = Array.ofDim[Long](queries.length)

    for (i <- 0 until queries.length) {
      val query = queries(i)
      val l = query(0)
      val r = query(1)

      // Initial cost: direct jump from l to r
      var minCost: Long = Math.abs(nums(l) - nums(r))

      // BFS to find all reachable states x' from l using only closest moves,
      // and simultaneously check the path cost l -> ... -> x' -> r (direct jump)
      val reachable = mutable.HashMap[Int, Long]() // Map: index -> min_cost_from_l
      val queue = mutable.ArrayBuffer[Int]()

      reachable.put(l, 0)
      queue.append(l)
      var head = 0

      while (head < queue.length) {
        val u = queue(head)
        head += 1
        val costU = reachable(u)

        // Check the path l -> ... -> u -> r (direct jump from u to r)
        val directCostToR = Math.abs(nums(u) - nums(r))
        val totalCost = costU + directCostToR
        minCost = Math.min(minCost, totalCost)

        // Explore next closest move
        val v = closest(u)
        val newCostV = costU + 1

        // If v hasn't been reached, or we found a shorter path to v (shouldn't happen here as edge weights are 1)
        if (!reachable.contains(v) || newCostV < reachable(v)) {
          reachable.put(v, newCostV)
          queue.append(v)
        }
      }

      // If r was reached via closest moves, the cost is captured by the loop when u=r
      // (as minCost = min(minCost, reachable(r) + |nums[r] - nums[r]|) = min(minCost, reachable(r))).

      results(i) = minCost
    }

    results
  }
}
