```scala
import scala.collection.mutable

object Solution {
  def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val n = nums.length

    // 1. Precompute closest(x) for all x
    val closest = new Array[Int](n)
    for (x <- 0 until n) {
      var minDiff: Long = Long.MaxValue
      var bestY: Int = -1

      // Check neighbors (x-1 and x+1)
      val neighbors = mutable.ArrayBuffer[Int]()
      if (x > 0) neighbors.append(x - 1)
      if (x < n - 1) neighbors.append(x + 1)

      if (neighbors.isEmpty) {
        closest(x) = x
        continue
      }

      for (y <- neighbors) {
        val diff = Math.abs(nums(x) - nums(y))
        if (diff < minDiff) {
          minDiff = diff
          bestY = y
        } else if (diff == minDiff) {
          // If differences are the same, choose the smaller index
          if (y < bestY || bestY == -1) {
            bestY = y
          }
        }
      }
      closest(x) = bestY
    }

    // 2. Process Queries using BFS for shortest path on the restricted graph structure
    val results = mutable.ArrayBuffer[Long]()

    for (query <- queries) {
      val l = query(0).toInt
      val r = query(1).toInt

      // Initial cost: direct jump from l to r
      var minCost: Long = Math.abs(nums(l) - nums(r))

      // BFS to find min cost path l -> ... -> x' -> r
      // We explore states x' reachable from l using only closest moves, 
      // and calculate the cost for the final jump to r from x'.

      // reachable maps index -> minimum cost from l using only 'closest' moves
      val reachable = mutable.HashMap[Int, Long]()
      val queue = mutable.ArrayBuffer[Int]()

      reachable.put(l, 0L)
